#include<bits/stdc++.h>
using namespace std;
struct node
{
	string a;
	int b;
}c[5010];
int cmp(node e,node d)
{
	if(e.b==d.b)
	{
		return e.a>d.a;
	}
	return e.b<d.b;
}
int n,m;
double pj;
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
    	cin>>c[i].a;
    	scanf("%d",&c[i].b);
	}
	m+=m/2;
    sort(c+1,c+n+1,cmp);
    int k=0;
	int tot=0;
	printf("%d ",c[n-m+1].b);
    tot=0;
	for(int i=n;i>=1;i--)
	{
		if(c[i].b>=c[n-m+1].b)
		{
			tot++;
		}
		else
		{

			break;
		}
	}
	printf("%d\n",tot);
	for(int i=n;i>=n-tot+1;i--)
	{
		cout<<c[i].a;
		printf(" %d\n",c[i].b);
	}
	return 0;
}
